"""
Standalone patch — writes mkt-context for Isaiah 44-47.
Run: python3 scripts/zc-context-isaiah-44-47-patch.py
Chapters: 44 (28v), 45 (25v), 46 (13v), 47 (15v) = 81 verses
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "44": {
    "1": "<p>Isaiah 44:1 opens the reassurance oracle after ch.43's indictment and grace: 've'attah shema Ya'aqov avdi, but now hear, Jacob my servant.' The 've'attah (but now) = the same pivot as 43:1 and 44:21, marking the transition from accusation back to comfort. 'Israel, whom I have chosen' (Yisrael asher bechharti = Israel whom I chose) — the divine election standing despite the sins catalogued in 43:22-28. The 'hearing' command (shema) frames the oracle as something Israel must actively attend to, not passively receive — the covenant summons to alertness.</p>",
    "2": "<p>'This is what the LORD says — he who made you, who formed you in the womb, and who will help you: Do not be afraid, Jacob my servant, Jeshurun whom I have chosen' — the Jeshurun address: Yeshurun (from yashar = upright, possibly a diminutive of affection, the idealized Israel) appears only four times in the OT (Deut 32:15; 33:5, 26; Isa 44:2) — always as a poetic name for Israel at its covenant best, as YHWH envisions it. 'Formed you in the womb' (yotsrekha mibbeten = the one who formed you from the womb) grounds divine faithfulness in Israel's very creation. The same 'formed in the womb' applies to Jeremiah's prophetic call (Jer 1:5) and to the Servant (49:5) — YHWH's purposes are prenatal, not contingent on subsequent behavior.</p>",
    "3": "<p>'For I will pour water on the thirsty land and streams on the dry ground; I will pour out my Spirit on your offspring, and my blessing on your children' — the double pouring: (1) 'ettsog mayim al-tsame = I will pour water on the thirsty land' and 'nozlim al-yabbashah = streams on the dry ground' = the physical water-miracle of the new Exodus (41:17-18; 43:19-20); (2) 'ettsog ruchi al-zar'ekha = I will pour out my Spirit on your offspring.' The ruach (Spirit = the same Spirit that hovered over the waters in Gen 1:2; that rested on the 70 elders in Num 11:25-29; that YHWH promised through Ezek 36:27: 'I will put my Spirit in you') poured out on the descendants. Joel 2:28 expands this into the great Spirit-promise: 'I will pour out my Spirit on all flesh' — quoted at Pentecost (Acts 2:17-18). The physical water and the spiritual outpouring are parallel: both are divine gifts that produce new life in the wasteland.</p>",
    "4": "<p>'They will spring up among the grass like willows beside flowing streams' — the botanical flourishing of the Spirit-watered community: 'vetsamchu bein chatsir ke'aravim al-yivlei mayim, they will spring up among the grass like willows beside flowing streams.' The chatsir (grass) and aravim (willows/poplars = the moisture-dependent trees of Ps 137:2: 'we hung our harps on the willows there') = the two vegetation types of a well-watered environment. The community that receives the Spirit-pouring is like the lush vegetation beside a stream: rooted, drinking continuously, growing naturally. The contrast with the idolaters who are 'feeding on ashes' (44:20) and the wilderness that will be transformed (41:18-19).</p>",
    "5": "<p>'One will say, I belong to the LORD, and another will take the name Jacob as his own. One will write on his hand, The LORD's, and will be called by the name of Israel' — the voluntary gentile identification with Israel's covenant community: four acts of covenant-confession by previously unaffiliated people: (1) verbal declaration ('I belong to YHWH' = ani leLYHWH = the possessive formula of covenant belonging); (2) adopting the name Jacob (yiqra beshem-Ya'aqov = will call himself by the name Jacob); (3) inscribing on the hand 'The LORD's' (yiktov yado leLYHWH = will write on his hand: to YHWH) — the tattooing or writing of divine ownership on the body, inverting the slave-mark and anticipating Rev 7:3's seal of God on the servants' foreheads; (4) taking the name Israel. These are descriptions of gentiles voluntarily and completely identifying with YHWH's covenant people — one of the clearest OT anticipations of the universal church.</p>",
    "6": "<p>'This is what the LORD says — Israel's King and Redeemer, the LORD of hosts: I am the first and I am the last; apart from me there is no God' — the most compressed form of the incomparability declaration: 'ani rishon va'ani acharon umibbal'adai en Elohim = I am the first and I am the last, and apart from me there is no God.' The three designations: (1) Israel's King (melek Yisrael = the divine kingship over the covenant community); (2) Israel's Redeemer (go'alo = his kinsman-redeemer, the one who pays the redemption price); (3) YHWH of hosts (the divine warrior). Together they establish YHWH's credentials for the claim. 'I am the first and last' (rishon ve'acharon) = the temporal frame: YHWH predates all and will outlast all. This formula appears in Rev 1:17; 2:8; 22:13 applied to the risen Christ — the Christological identification is explicit in John's Apocalypse.</p>",
    "7": "<p>'Who is like me? Let him come forward, announce it, and lay it out before me. Who has declared from of old what is to come, since I established the ancient people? Let them tell us what lies ahead' — the incomparability challenge with the prediction-test: 'umi khemoni yiqra veyaggideha ve'ya'arkhehah li = who is like me, let him call out and declare it and set it before me.' The court-of-evidence standard: any divine claimant must be able to announce in advance what is coming. 'Since I established the ancient people' (misiml'i am-olam = since my placing of the people of eternity) = since the founding of Israel as YHWH's covenant people from primordial time. The challenge is specifically about the Cyrus-oracle: no other deity or divination system declared Cyrus's role in advance.</p>",
    "8": "<p>'Do not tremble, do not be afraid. Did I not tell you long ago and declare it? You are my witnesses: is there any God apart from me? There is no Rock — I know of none' — the Rock-claim: 'hatsur = the Rock' (from tsur = the craggy rock of the desert, the immovable stronghold; Deut 32:4: 'the Rock, his work is perfect, for all his ways are justice'; Ps 18:2: 'YHWH is my rock, my fortress, my deliverer; my God is my rock, in whom I take refuge'). 'There is no Rock — I know of none' (ve'en tsur bal-yadati = and there is no rock; not one I know of) = the emphatic denial: not just that other divine rocks are weaker than YHWH, but that YHWH in his comprehensive knowledge finds no other rock-deity in existence. 1 Cor 10:4 identifies Christ as the Rock who followed Israel in the wilderness: the divine Rock of Isaiah becomes the pre-incarnate Christ.</p>",
    "9": "<p>'All who fashion idols are worthless, and the things they prize are of no use. Their own witnesses can neither see nor know — so they will be put to shame' — the verdict on idol-makers: 'yotserei fessel kullam tohu = fashioners of idol, all of them are chaos/nothing.' The tohu (chaos = the same pre-creation void of Gen 1:2 applied in 41:29 to the idols' works) applied to the idol-makers themselves — the craftsmen share the ontological status of their creation. 'The things they prize are of no use' (vachamodeihem bal-yo'ilu = and their precious things are of no profit) — the emotional investment in idols ('prize/cherish them') does not compensate for their functional uselessness. 'Their own witnesses can neither see nor know' (vedeihem hemma bal-yiru vebal-yede'u = their witnesses they are, they cannot see and they cannot know) — the idols' own 'witnesses' (the worshipers who testify to their effectiveness) are themselves blind and ignorant.</p>",
    "10": "<p>'Who would shape a god or cast a metal idol that profits him nothing?' — the rhetorical absurdity: 'mi-yatsar el = who shapes a god?' The question expects the answer: no rational person would. 'Cast a metal idol that profits him nothing' (umassekha yatsaq lelo yo'il = and a molten image pour out — for no profit) — the yo'il (profit/benefit = from ya'al = to be of benefit, the pragmatic test: does it help?) applied to the fundamental value-proposition of idol-worship. The entire idol-polemic of vv9-20 is essentially a sustained pragmatic argument: the idol costs enormous labor to produce and returns zero benefit.</p>",
    "11": "<p>'Look — all his associates will be put to shame, and the craftsmen are, after all, only human. Let them assemble together and stand up; they will be terrified and shamed together' — the guild of shame: 'hen kol-chaveiro yevoshu = see, all his associates/fellows will be shamed.' The chaverim (associates/members of the same guild = the craftsmen's professional guild who collaborate in idol-production) share the shame of their product. 'The craftsmen are, after all, only human' (vecharashim hemmah me'adam = and the craftsmen — they are from human/of humanity) — the point: the makers of 'gods' are themselves merely human beings. 'Let them assemble together and stand up' (yitqabetsu kulam ya'amodu = let them all assemble and stand) — the challenge to the assembled idol-guild: stand and defend your craft. 'They will be terrified and shamed together' (yifchadu veyevoshu yachdav = they will fear and be shamed together).</p>",
    "12": "<p>'The blacksmith works the iron over burning coals; he beats it into shape with hammers, forging it with his strong arm. But he grows hungry and loses his strength; if he drinks no water, he grows faint' — the iron-idol's maker is himself vulnerable: 'charash barzel ma'atsad vepa'al bapecham = the iron-craftsman with a cutting tool works in the coals.' The process: charash barzel (blacksmith) works in the coals (bapecham = in the burning coal-fire), beats into shape (vayyitseruhu bepattishim = hammers it into shape), and forges (vyep'alehu bizroa kocho = works it with his arm of strength). The irony: 'but he grows hungry and loses his strength' (gam-ra'ev ve'en koach = and also he is hungry and has no strength). 'If he drinks no water, he grows faint' (lo-shata mayim vayyi'af = has not drunk water and grows faint). The one making the 'almighty god' cannot sustain himself through the manufacturing process — he needs water breaks. The creator of the alleged deity is dependent on the same physiological necessities as any laborer.</p>",
    "13": "<p>'The carpenter measures the wood with a line; he draws an outline with chalk. He shapes it with chisels and marks it with a compass, carving it into the shape of a man — a handsome human figure — to be set up in a house' — the detailed woodworking process: 'charash etsim natah qav = the wood-craftsman stretches a measuring line.' The surveyor's tools applied to idol-making: (1) qav (measuring line = the carpenter's chalk-line for marking straight cuts); (2) maqtsuah (a chalk/marker = the marking tool); (3) maatsad (a chisel = the shaping tool); (4) mechuga (a compass = the instrument for drawing circles and ellipses). The precision tooling: the idolater uses the most sophisticated carpentry tools of the ancient world to produce 'a handsome human figure' (ketavnit ish kemireh adam = like the beauty of a man, like the appearance of a human). The irony: YHWH made humans in his image (Gen 1:26-27); the idolater makes his god in the image of a human. The sequence is inverted.</p>",
    "14": "<p>'He cuts down cedars; he selects a cypress or an oak and lets it grow strong among the trees of the forest. He planted it, and the rain made it grow' — the origin of the idol-material: 'likrot lo arazim = to cut for himself cedars' (the prestigious Lebanon cedar) or 'yiqach tirzah veallon = he takes a holm-oak or an oak.' 'He planted it, and the rain made it grow' (nata oren vageshem yegaddel = he planted a pine and the rain made it great). The theological point: the wood that becomes the idol was planted by the idolater and grew by YHWH's provision of rain. The rain that made the tree grow is the same rain that YHWH provides (Job 5:10: 'he gives rain on the earth and sends water on the fields'). YHWH's sustaining of creation provides the raw material for the idol that denies him.</p>",
    "15": "<p>'Then the wood serves as fuel for the man. He burns part of it to warm himself; he kindles a fire and bakes bread. But he also fashions a god from it and worships it — carves an idol and bows down to it' — the bifurcation of purpose: 'vehayah le'adam levarer = and it is for a man for fuel.' Part one: 'yiqqach mehem vayycham af-yasiq veyofeh lechem = he takes from them and warms himself; he also kindles and bakes bread.' Part two: 'af-yipsol el vayishtachu asah pessel vayisgod-lamo = he also fashions a god and worships it; he made a carved image and bows down to it.' The same tree, the same hands, the same day — fuel in the morning, deity in the afternoon. The satire exposes the arbitrariness of idolaters' category distinctions: what makes one half 'firewood' and the other half 'God' is purely the craftsman's decision, not any property of the material itself.</p>",
    "16": "<p>'Half of it he burns in the fire; over the coals he roasts meat, eats his fill, and warms himself, saying, Aha, I am warm; I can feel the heat' — the half-and-half narrative: 'chatsiyo saraf bemoh-esh, half of it he burned in the fire.' The meals and warmth from half: 'al-chatsiyo basar yochal = over half of it he roasts meat'; 'yishba af-yicham ve'yomar heach chamoti, he eats his fill and also warms himself and says: aha! I am warm; I have seen the fire!' The 'aha!' (heach = the exclamation of satisfaction, the sound of a person who has gotten what they needed from the fire) is the embodiment of treating fire as pure utility — the physical pleasure of warmth and roasted meat. The idolater cannot perceive the theological absurdity because his belly is full and he is warm.</p>",
    "17": "<p>'But the rest of the wood he makes into his god, into a carved image, and bows down to it and worships it. He prays to it and says, Save me — you are my god' — the other half: 'usheerito le'el asah lefesellov yisgod-lo = and the rest of it into a god he makes; his carved image he bows down to it.' 'He prays to it and says, Save me — you are my god' (yitpallel elav veyomar hatsiyleni ki eli-attah = he prays to it and says: save me, for you are my god). The prayer ('save me') directed to the piece of wood that survived the cooking fire. The same root yatsal (to save/deliver) that YHWH uses of himself throughout these chapters: 'apart from me there is no savior' (43:11). The wooden object that just cooked last night's meat is now the object of the most urgent human prayer: 'save me.'</p>",
    "18": "<p>'They have no knowledge or understanding; their eyes are plastered shut so they cannot see, and their minds are closed so they cannot grasp it' — the anatomy of spiritual blindness: 'lo yade'u velo yavinu = they have no knowledge and no understanding.' 'Their eyes are plastered shut so they cannot see' (ki tach me'rot eineihem mire'ot = for their eyes are smeared over from seeing) — tach (to plaster/smear = the daubing of plaster over a surface to seal it; the same root as the plastering of a house in Lev 14:42). The eyes are sealed over, deliberately plastered shut. 'And their minds are closed so they cannot grasp it' (levotham mahahskel = their hearts from understanding). The theological diagnosis: idolaters are not in the grip of an understandable error but in a condition of willful blindness — the rational faculty itself has been sealed against the obvious evidence.</p>",
    "19": "<p>'No one stops to think; no one has the knowledge or insight to say: Half of this I burned — I even baked bread over its coals; I roasted meat and ate it. Should I really make an abomination out of what is left? Should I bow down to a block of wood?' — the absence of rational self-reflection: 'velo-yashiv el-libbo velo da'at velo tevunah, and not one returns it to his heart; and there is no knowledge and no understanding.' The returning-to-one's-heart (yashuv el-libbo = the OT phrase for rational reflection, self-examination: 1 Kgs 8:47; Job 1:5) is absent. The unavailable question: 'halo shethi lo aseiti gam-aseiti al-gahalav = is it not that half of it I burned? I even baked bread on its coals.' 'Should I really make an abomination out of what is left?' (avudul lish'er yisgod = and from the rest of it an abomination shall I make?) — toevah (abomination) = the strongest term of moral-religious offense. The idolater cannot ask the obvious question because his mind is sealed (v18).</p>",
    "20": "<p>'He is feeding on ashes; a deceived mind has led him astray. He cannot save himself or bring himself to say, Is this thing in my hand not a fraud?' — the diagnosis: 'ro'eh efer lev huttal hittahu = he feeds on ashes; a deceived heart has turned him aside.' The efer (ashes = the final residue of what was burned — he feeds on ashes because his 'god' is a piece of wood from the same tree that produced the cooking fire's ashes). The huttal (deceived = from natal = to be misled, diverted from the path; the same root as the deception of Eve in Gen 3:13: 'the serpent deceived me'). 'He cannot save himself' (velo yatsal et-nafshov = and he cannot deliver his soul) — the ultimate irony: the idol he prays to for salvation ('save me' v17) cannot be recognized as fraudulent because the idolater's mind cannot form the question. 'Is this thing in my hand not a fraud?' (hasheger beyemini = is the lie in my right hand?) — the self-incriminating question the sealed mind cannot ask.</p>",
    "21": "<p>'Remember all this, Jacob and Israel, for you are my servant. I formed you; you are my servant. Israel, I will not forget you' — the return to Israel after the idol-polemic: 'zekhorah elleh Ya'aqov veYisrael ki avdi-attah, remember these things, Jacob and Israel, for you are my servant.' The idol-polemic (vv9-20) was implicitly addressed to the exiles who were surrounded by Babylonian idol-worship — the reminder 'you are my servant' reasserts Israel's distinct identity after the extended satire. 'I will not forget you' (lo enshakehah = I will not forget you) — the divine memory of Israel: the covenant commitment that means YHWH does not lose track of his people even in Babylon. Isa 49:15-16: 'Can a mother forget the baby at her breast? ...I will not forget you. See, I have engraved you on the palms of my hands.'</p>",
    "22": "<p>'I have swept away your transgressions like a cloud, your sins like morning mist. Return to me, for I have redeemed you' — the forgiveness oracle: 'machiti kha'av pisha'akha = I have wiped away like a cloud your transgressions.' The machah (to wipe/blot out = the same root as 43:25: 'I am he who blots out your transgressions') applied to a cloud (av = a dense, heavy thundercloud) and morning mist (khe'anan = the thin early morning fog that dissipates when the sun rises). The transgressions are like clouds in two senses: (1) they obscure the relationship with YHWH as clouds obscure the sun; (2) they are impermanent — wiped away as easily as a cloud by YHWH's act. 'Return to me, for I have redeemed you' (shuva elai ki ge'altikhah = return to me, for I have redeemed you) — the redemption (perfect tense: already accomplished in YHWH's purpose) as the ground for the call to return. The sequence: YHWH acts first (forgives, redeems), then calls for the human response (return/repent).</p>",
    "23": "<p>'Shout for joy, O heavens, for the LORD has done it! Shout aloud, O depths of the earth! Burst into song, O mountains, O forest, every tree in it! For the LORD has redeemed Jacob and displays his glory in Israel' — the cosmic celebration: 'ronu shamayim ki-asah YHWH = sing for joy, O heavens, for YHWH has done it!' The full creation invited to celebrate: heavens (shamayim), depths of the earth (tachtiyot erets), mountains (harim), and the entire forest (ya'ar vekhol-ets bo). The non-human creation as worship-community: trees and mountains singing is the eschatological vision of creation's liberation (Rom 8:21: 'the creation itself will be liberated from its bondage to decay'). 'The LORD has redeemed Jacob' (ki ga'al YHWH Ya'aqov = for YHWH has redeemed Jacob) and 'displays his glory in Israel' (uveYisrael yitpa'ar = and in Israel he glorifies himself) — the redemption of Israel is the display of YHWH's kavod to all creation.</p>",
    "24": "<p>'This is what the LORD says — your Redeemer, who formed you in the womb: I am the LORD who made all things; I alone stretched out the heavens; by myself I spread out the earth' — the Creator's credentials for the Cyrus-oracle: 'ko-amar YHWH go'alekhah veyotsrekha mibbeten = thus says YHWH your redeemer and your former from the womb.' Three creation claims: (1) 'I am the LORD who made all things' (anoki YHWH oseh kol = I, YHWH, the maker of everything); (2) 'I alone stretched out the heavens' (noteh shamayim levaddi = the one who stretched out the heavens by myself/alone); (3) 'by myself I spread out the earth' (roqa ha'arets mi-itti = the one who spread out the earth — who was with me?). The mi-itti (who was with me?) = the rhetorical question: no one. YHWH stretched out the heavens alone — no partner, no divine council member, no demiurge. This is the creation-credential that authorizes him to appoint Cyrus.</p>",
    "25": "<p>'Who thwarts the omens of impostors and makes fools of diviners, who turns back the wise and makes their knowledge into nonsense' — YHWH's counter-operation against Babylon's knowledge systems: 'meper otot baddim = the one who thwarts/breaks the signs of liars/diviners.' The baddim (boasters/imposters = the false prophets and professional diviners who claimed predictive knowledge; Jer 50:36: 'a sword against her false prophets! They will become fools'). 'Makes fools of diviners' (veqosemim yeholelel = he makes the diviners into madmen/fools) — the holelim (mad ones = those who are deranged; Eccl 1:17; 2:2: 'what is done is madness'). The Babylonian astronomical and omen literature represented the most sophisticated knowledge system in the ANE; YHWH dismisses it as the work of baddim. 'Turns back the wise and makes their knowledge into nonsense' (meshib chakhamim achor veda'tam yesakkeil = the one who turns back the wise and makes their knowledge foolish) — the wisdom of Babylon (cf. 1 Cor 1:20: 'has not God made foolish the wisdom of the world?').</p>",
    "26": "<p>'Who fulfills the word of his servant and carries out the plan of his messengers, who says about Jerusalem, It will be inhabited, and about the towns of Judah, They will be rebuilt, and I will raise up their ruins' — the contrast with Babylon's diviners: YHWH validates not the omens of impostors (v25) but 'the word of his servant' (devar avdo = the prophetic word of his servant = Isaiah's oracles). 'The plan of his messengers' (atzat mala'akhav = the counsel of his ambassadors/messengers = the prophetic messages). 'Says about Jerusalem, It will be inhabited' (ha'omer liYrushalayim tushekhab = who says to Jerusalem: she will be inhabited) — the specific fulfillment: Jerusalem rebuilt after Babylon. 'About the towns of Judah, They will be rebuilt' (velehare Yehudah tivvaneynah = and the cities of Judah they will be rebuilt). These are the oracles whose fulfillment through Cyrus validates the prophetic office and exposes the Babylonian diviners.</p>",
    "27": "<p>'Who commands the ocean depths, Dry up! and says to the rivers, I will make you run dry' — the Exodus-allusion and Cyrus's campaign: 'ha'omer latsulah choravi = the one who says to the deep: dry up!' The tsulah (the deep/ocean = the same tehom of Gen 1:2 and Exod 15:5: 'the deep covers them') commanded to dry up. This double-references: (1) the Red Sea crossing (Exod 14:21-22) where YHWH dried the sea; (2) Cyrus's diversion of the Euphrates when he entered Babylon (539 BCE) — Herodotus (1.189-191) describes how Cyrus diverted the Euphrates into a lake to expose the riverbed as an entry point under Babylon's walls. The same YHWH who dried the Red Sea dried the Euphrates for Cyrus.</p>",
    "28": "<p>'Who says of Cyrus, He is my shepherd; he will carry out everything I want him to do, who says of Jerusalem, She will be rebuilt, and of the temple, Your foundation will be laid' — the climactic Cyrus-naming: 'ha'omer leKhoresh ro'i = the one who says to Cyrus: my shepherd.' The naming of Cyrus (Hebrew: Koresh = Persian: Kuraš = Greek: Kyros) by name approximately 150 years before his birth is the most dramatic fulfilled-prophecy claim in Isaiah. The title ro'i (my shepherd = the shepherd-king of YHWH's choosing, the same term as the messianic shepherd of Ezek 34:23; 37:24 applied to the Davidic king) given to a pagan Persian king. 'He will carry out everything I want him to do' (vekhol-chefetsi yashlem = and all my pleasure/desire he will complete) — Cyrus's career is the fulfillment of YHWH's divine counsel (chafets). The historical Cyrus Cylinder (538 BCE) confirms: Cyrus decreed the return of all exiled peoples to their homelands and the rebuilding of their temples — including the Jerusalem temple (Ezra 1:1-4; 6:3-5).</p>"
  },
  "45": {
    "1": "<p>Isaiah 45:1 opens the Cyrus oracle proper: 'ko-amar YHWH limshicho leKhoresh, thus says YHWH to his anointed, to Cyrus.' The mashiach (anointed = the Hebrew term for messiah, used for Israelite kings anointed with oil at coronation: 1 Sam 10:1; 16:13; 2 Sam 2:4; and for priests: Exod 29:7; Lev 4:3) applied to a gentile pagan king is unprecedented in the OT — Cyrus is the only non-Israelite ever called YHWH's mashiach. This does not make Cyrus the Messiah in the NT sense, but it does show YHWH's sovereign authority to commission and anoint any king, regardless of religion. 'Whose right hand he has grasped to subdue nations before him' (asher-chazaqti biyminoh = whose right hand I have grasped) = the same hand-grasping of 41:13 for Israel. Babylon's gates falling for Cyrus was historical fact: the Babylonian Chronicle records that Cyrus's general Ugbaru entered Babylon without battle, and Cyrus himself entered the city shortly after.</p>",
    "2": "<p>'I will go before you and make the rough places smooth; I will break the gates of bronze in pieces and cut through the bars of iron' — the divine escort: 'ani lefanekha elek vehadorim ayashsher = I before you will go and the rough/swelling places I will level.' The divine warrior going before his instrument: the same imagery as 40:3 (preparing YHWH's way) now applied to preparing Cyrus's way. 'The gates of bronze' (daltot nechoshet = bronze doors): Herodotus (1.179) describes Babylon's inner gateways as having bronze gates — 'bronze gates' became proverbial for Babylon's impregnability. 'Bars of iron' (uvrichei barzel = and bars of iron) = the iron locking-bars that secured the massive gates. The historical account: Cyrus diverted the Euphrates and entered under the bronze water-gates — the famous gates literally were bypassed from below.</p>",
    "3": "<p>'I will give you the treasures stored in darkness and the wealth hoarded in secret places, so that you may know that I, the LORD, am the God of Israel who has called you by name' — the divine enrichment of Cyrus and its missionary purpose: 'venatatti lekha otsarot choshekh = and I will give you the treasures of darkness.' The treasures of darkness (otsarot choshekh = treasuries in the dark = the hidden vaults of the Babylonian temples and palace storehouses) — historically, Babylon's temples contained enormous wealth accumulated from centuries of tribute and plunder (including the treasures from Jerusalem's temple, 2 Kgs 24:13; 25:13-17). The purpose: 'lema'an teda ki ani YHWH = so that you may know that I, YHWH.' Even Cyrus, who did not know YHWH (v4: 'though you did not know me'), is given material evidence of who directed his career.</p>",
    "4": "<p>'For the sake of my servant Jacob, and Israel my chosen, I called you by your name; I gave you a title of honor, though you did not know me' — the motivation for Cyrus's divine appointment: 'lema'an avdi Ya'aqov veYisrael bechiiri = for the sake of my servant Jacob and Israel my chosen one.' YHWH's use of Cyrus is not because Cyrus deserves it or even because Cyrus is aware of it — but entirely 'for the sake of Jacob.' 'I gave you a title of honor, though you did not know me' (va'akunnekha velo yedatani = and I surnamed/titled you, though you did not know me) — the kinnah (title/surname/honorific = a formal designation of identity and role) given to Cyrus despite his ignorance of YHWH. This is the most explicit statement of divine sovereignty using a non-believing instrument in the OT: YHWH's purposes are accomplished through those who don't recognize him as the one directing them.</p>",
    "5": "<p>'I am the LORD, and there is no other; besides me there is no God. I equipped you, though you did not know me' — the repeated monotheistic assertion: 'ani YHWH ve'en od = I, YHWH, and there is no other.' The en od (there is no other = not merely 'no other god' but 'no other' of any kind in the divine category) = the absolute monotheism. 'Besides me there is no God' (mibbal'adai en Elohim = apart from me there is no God). 'I equipped you' (va'azarezekha = I girded/equipped you, from azar = to gird for strength or battle) — YHWH equipped Cyrus for his campaigns. The repeated 'though you did not know me' (velo yedatani) = the divine freedom to act through the unknowing: YHWH's purposes are not limited by the awareness or faith of his instruments.</p>",
    "6": "<p>'So that from the rising of the sun to where it sets, people may know there is no one besides me; I am the LORD, and there is no other' — the universal-knowledge purpose of the Cyrus-deployment: 'lema'an yede'u mimizrach-shemesh = so that they may know from the rising of the sun.' The entire inhabited world ('from the rising to the setting of the sun' = the complete east-west span) is the target audience of the Cyrus-demonstration. YHWH deploys Cyrus not merely to save Israel but to demonstrate his uniqueness to the entire world. The missionary dimension of Israel's rescue: when YHWH saves his people through an impossible means (a pagan emperor), the watching world learns who YHWH is. The 'may know' (yede'u = the covenant-knowing of experiential recognition) is the purpose of all YHWH's historical acts throughout Isaiah 40-55.</p>",
    "7": "<p>'I form light and create darkness; I make peace and create disaster; I, the LORD, do all these things' — the most theologically challenging verse of ch.45: 'yotser or ubore choshekh oseh shalom ubore ra = forming light and creating darkness, making peace and creating evil/disaster.' The Hebrew ra (evil/disaster = both moral evil and catastrophic calamity; in context of YHWH's speech this is best read as calamitous disaster/adversity rather than moral evil). The verse is structured as an anti-dualism polemic: Persian Zoroastrianism posited two co-eternal, co-equal deities — Ahura Mazda (the good principle, creator of light) and Angra Mainyu (the evil principle, creator of darkness) locked in eternal conflict. YHWH's claim: he is the sole ultimate cause of both light/darkness and peace/adversity. There is no second divine principle. This does not make YHWH the author of moral evil but asserts that even calamity is within his sovereign control and purpose.</p>",
    "8": "<p>'Rain down, O heavens, from above, and let the skies pour down righteousness; let the earth open up and salvation spring forth, and let righteousness grow up with it; I, the LORD, have created it' — the prayer for the new-creation outpouring: 'harziyfu shamayim mima'al = rain down, O heavens from above.' The heavens are invited to rain (harziyfu = the intensive form of razaf = to drip/pour) their tsedaqah (righteousness = the covenant-right-ordering of all relationships). 'Let the earth open up and salvation spring forth' (vitetpetach erets veyiphreru yesha = and let the earth open and let salvation bear fruit) — salvation as crop growing from rain-watered soil. 'And let righteousness grow up with it' (utsedaqah titsmach yachdav = and righteousness spring up together). The meteorological-agricultural imagery: righteousness falls from heaven, salvation grows from earth — a vertical and horizontal integration of divine gift. This verse underlies John 3:16's gift-from-above theology and the parable of the sower (Matt 13:3-9).</p>",
    "9": "<p>'Woe to him who quarrels with his Maker — a mere potsherd among potsherds of earth! Does the clay say to the one who shapes it, What are you making? or Your work has no handles?' — the woe against challenging the divine use of Cyrus: 'hoy rib et-yotsro = woe to the one who strives with his maker.' The hoi (woe = the prophetic grief-cry that introduces a judgment oracle: 1:4; 5:8-23; 10:1) against the one who riv (disputes/quarrels with = the same legal term as the divine courtroom disputations of chs.41-44) his Maker. 'A mere potsherd among potsherds of earth' (cheres et-charshe adamah = a shard among the shards of the earth) — the human being who disputes with YHWH is merely a piece of broken pottery disputing with the potter. 'Does the clay say to the one who shapes it, What are you making?' (hayomer chomer leyotsero mah-taaseh = will the clay say to its potter: what are you making?) — the absurdity of the creature questioning the creator's design (Jer 18:4-6; Rom 9:20-21: 'Does the pot say to the potter: Why did you make me like this?').</p>",
    "10": "<p>'Woe to him who says to a father, What are you fathering? or to a woman, What are you in labor with?' — the second woe extending the creator-creature analogy to parenthood: 'hoy omer le'av mah-tolid = woe to the one who says to a father: what are you fathering?' The father-child and mother-child relationships as analogies for YHWH-Israel: just as a child cannot dictate the circumstances of its own birth, Israel cannot dictate to YHWH how he accomplishes Israel's redemption (through Cyrus). 'Or to a woman, What are you in labor with?' (vela'isha mah-techalin = and to the woman: what are you giving birth to?) — the birth-labor analogy continues the childbirth imagery of 42:14 (YHWH crying out like a woman in labor). The parent-child relationship as the ground of both divine authority over the redemption-plan and divine commitment to the child's existence and flourishing.</p>",
    "11": "<p>'Thus says the LORD, the Holy One of Israel, and his Maker: Will you question me about my children, or give me orders about the work of my hands?' — YHWH's direct response to the objectors: 'ko-amar YHWH qedosh Yisrael veyotsero = thus says YHWH, the Holy One of Israel, and his Maker.' The dual title (Holy One of Israel + Maker) responds to both the 'potter' and 'parent' analogies: YHWH is the maker/craftsman of Israel (potter) and the parent. 'Will you question me about my children?' (ha'otiyot shealuni = will you ask me about the things to come?) — the objectors who question YHWH's use of Cyrus are questioning the divine parent's choices about his own children. 'Or give me orders about the work of my hands?' (uveal-me'aseh yadai tetsavvuni = and about the work of my hands will you command me?) — the creature cannot command the Creator about his own design.</p>",
    "12": "<p>'I made the earth and created mankind upon it; with my own hands I stretched out the heavens, and I commanded all their starry host' — the Creator's credentials: 'anoki asiti erets ve'adam aleyhah barati = I made the earth and mankind on it I created.' Three creation-acts: (1) made the earth; (2) created mankind on it; (3) 'ani yadai nateu shamayim = my own hands stretched out the heavens.' The 'I commanded all their starry host' (vekhol-tseva'am tsivviti = and all their host I commanded) — the stars as YHWH's army under his direct command (40:26: 'he leads out their host by number, calling each by name'). The contrast with Babylonian astrology that treated the stars as independent divine powers governing fate: YHWH commands the stars; they do not command him or the course of history.</p>",
    "13": "<p>'I have stirred him up in righteousness, and I will make all his paths straight; he shall build my city and set my exiles free — not for price or reward, declares the LORD of hosts' — the righteous commission of Cyrus: 'ani ha'irotiv bitsedaqah = I have stirred him up in righteousness/for the right purpose.' The stirring up in tsedaqah (righteousness = for the sake of covenant right-ordering; not 'for Cyrus's personal righteousness' but 'for my righteous purpose'). 'He shall build my city' (hu-yivneh iri = he will build my city = Jerusalem) and 'set my exiles free' (galuti yeshalech = he will release my exile/exiles). Historically: Cyrus's edict (538 BCE, Ezra 1:1-4) decreed the return of the Jewish exiles and the rebuilding of the Jerusalem temple. 'Not for price or reward' (lo vemechir velo vishochad = not for payment and not for a bribe) — Cyrus freed Israel without demanding tribute or personal payment, which is historically accurate: the Cyrus Cylinder shows him as presenting himself as a liberator, not an extractor.</p>",
    "14": "<p>'Thus says the LORD: The wealth of Egypt and the merchandise of Cush, and the Sabeans — tall men — shall come over to you and be yours; they shall follow you; they shall come over in chains and bow down to you, pleading, Surely God is in you, and there is no other, no god besides him' — the nations' recognition oracle: 'yegi Mitsrayim usechar Kush = the toil/tribute of Egypt and the merchandise of Cush.' Egypt (Mitsrayim), Cush (Ethiopia), and the Sabeans (shevan'im = the South Arabian tribe of Sheba, known for trade in gold, spices, and precious stones, 1 Kgs 10:1-13; Ezek 27:22) = the three great trading civilizations of the south, representing the wealth of the known world. 'Come over in chains and bow down to you' (ya'avoru velaykh yihyu = they will come over and to you they will belong; vealayikh yishtaghu = and to you they will bow) — not chains of conquest but possibly the chains of tribute-bearing submission. The climax: 'akh bekha El ve'en od = surely in you is God, and there is no other.' The Gentile recognition formula: seeing YHWH's act through Israel, the nations confess what Israel had claimed all along.</p>",
    "15": "<p>'Truly you are a God who conceals himself, O God of Israel, the Savior' — the deus absconditus: 'aken attah El mistatter Elohei Yisrael moshi'a = truly you are a God who hides himself, O God of Israel, the Savior.' The aken (truly/surely = the affirmation that follows on evidence) + El mistatter (a God who hides/conceals himself = from sathar = to hide, conceal; Ps 10:11: 'he hides his face and never sees'). The hester panim (hiding of the face) was the OT's theological term for divine absence during disaster and exile (Ps 13:1; 88:14; Isa 8:17). The paradox: the hidden God is the Savior God. The concealment is not absence but the invisibility of the divine action working through Cyrus — only retrospectively visible as YHWH's hand. Martin Luther built his theology of the cross on this verse: God is most hidden (crucified) when he is most powerfully saving.</p>",
    "16": "<p>'They are all put to shame and confounded; together all the makers of idols go off in disgrace' — the contrast: idol-makers shamed vs. Israel saved: 'bosh veham kol-hem yachdav halekhu vekhalimat choreshei tselilim = they will be ashamed and also confounded, all of them together; they will go in disgrace, the craftsmen of idols.' The makers of images go off (halekhu = they went, the perfect of certainty) in disgrace (vekhalimat = and with disgrace/confusion = the shame of public failure). The contrast with Israel in v17 is precisely drawn: idol-makers → shame/disgrace; Israel → everlasting salvation/never put to shame.</p>",
    "17": "<p>'But Israel is saved by the LORD with an everlasting salvation; you will not be ashamed or confounded for ages everlasting' — the everlasting-salvation promise: 'Yisrael noshia beLYHWH teshu'at olamim = Israel is saved by YHWH with salvation of eternities.' The olamim (eternities/ages = plural of olam = the strong form of the permanent unending character of the salvation) — this is not merely temporal rescue from Babylon but permanent covenant-status restoration. 'You will not be ashamed or confounded for ages everlasting' (lo tevoshu velo tikkalemu ad-olmei ad = you will not be shamed and will not be confounded unto the ages of eternity). The double negative (lo...velo) = emphatic: not at all ashamed, not at all confounded. The antithesis to the shame of the exile and the shame of the idol-makers (v16): what they experience permanently (shame), Israel will not experience again.</p>",
    "18": "<p>'For thus says the LORD, who created the heavens — he is God — who formed the earth and made it, who established it and did not create it a chaos but formed it to be inhabited: I am the LORD, and there is no other' — the creation-purpose statement: 'ki ko-amar YHWH bore hashamayim hu ha'Elohim = for thus says YHWH, the creator of the heavens, he is the God.' The creation-credential: (1) bore hashamayim (creator of the heavens); (2) yotser ha'arets va'asah (former and maker of the earth); (3) hu khonenah (he established it); (4) lo-tohu bera'ah lashevet yetsarah (he did not create it tohu/chaos but formed it for inhabitation). The theological point: YHWH's creational purpose is order and habitation (lashevet = for sitting/dwelling/inhabiting), not chaos (tohu = the Gen 1:2 void). The exile (Israel driven from its land = dispossession and disorder) contradicts YHWH's creational intent — which is exactly why the restoration is necessary and certain: YHWH's creative purpose cannot be permanently frustrated.</p>",
    "19": "<p>'I did not speak in secret, in a land of darkness; I did not say to the offspring of Jacob, Seek me in a waste. I, the LORD, speak truth; I declare things that are right' — YHWH's transparent revelation contrasted with pagan oracle-systems: 'lo beseter dibarti bemaqom erets choshekh = I did not speak in secret, in a place of dark earth.' The Babylonian divination system required elaborate ritual, initiated specialists, and secret knowledge to interpret divine communication. Greek oracles (Delphi) were famously ambiguous. YHWH's self-contrast: his word is spoken in the open, not in a land of darkness or chaos. 'I did not say to the offspring of Jacob, Seek me in a waste' (lo amartiy lizera Ya'aqov tohu baqshuni = I did not say to the seed of Jacob: seek me in chaos) — YHWH's call is not to seek him in the tohu (chaos/waste) but in the ordered structure of covenant, Torah, and worship. Cf. John 18:20: 'I have spoken openly to the world... I said nothing in secret.'</p>",
    "20": "<p>'Assemble and come; draw near together, you survivors of the nations. Those who carry around their wooden idols and pray to a god that cannot save have no understanding' — the universal invitation to the nations: 'hiqqavetsu uvo'u hitnaggoshu yachdav pleytei haggoyim = assemble and come; draw near together, survivors of the nations.' The peleytei haggoyim (survivors of the nations = those who have escaped the Cyrus-conquest, the remnant of the Babylonian empire's subject peoples) are invited to the divine court. 'Those who carry around their wooden idols' (hannose'im et-ets pitslam = those who carry around their carved wooden image) — the idol-carrying procession: in Babylon, the great Akitu festival featured the gods being carried in procession through the city. 'Pray to a god that cannot save' (vamitpallelim el-el lo yoshia = and praying to a god that cannot save) — the ultimate pragmatic test of deity: can it save (yasha)? The test YHWH will pass in v21-22.</p>",
    "21": "<p>'Declare your case and present your arguments; let them consult together. Who foretold this from long ago? Who declared it from of old? Was it not I, the LORD? There is no other god besides me — a God who is righteous and saves; there is none besides me' — the courtroom verdict: 'haggidu vehaggishu af yio'atsu yachdav = declare and present; also let them consult together.' The nations' case invited and then dismissed: 'mi-hishmi'a zot miqedem = who made this heard from antiquity?' The prediction-test applied to Cyrus's fulfillment: who predicted all this? 'Was it not I, the LORD?' (halo anoki YHWH ve'en od Elohim = was it not I, YHWH, and there is no other God?). The verdict: 'El-tsaddiq umoshi'a en zulati = a righteous God and a Savior — there is none besides me.' The tsaddiq (righteous/just = the one who acts in accordance with covenant right-order) combined with moshi'a (Savior = the one who delivers) = YHWH is both just (the exile was just punishment) and saving (the restoration is genuine salvation).</p>",
    "22": "<p>'Turn to me and be saved, all the ends of the earth! For I am God, and there is no other' — the most explicit universal salvation-invitation in the OT: 'penu elai vehivashe'u kol-afsei-erets = turn to me and be saved, all the ends of the earth!' The penu (turn = the same root as teshuvah/repentance: turning from and turning toward) elai (to me = YHWH) directed to kol-afsei-erets (all the ends of the earth = the maximally inclusive geographic scope, encompassing every inhabited region). 'For I am God, and there is no other' (ki-ani El ve'en od = for I am God and there is nothing more/other) — the monotheistic ground for the universal invitation: there is no other deity to turn to, so the invitation extends to all. John 12:32: 'I, when I am lifted up from the earth, will draw all people to myself.' Matt 28:19: 'Go and make disciples of all nations.'</p>",
    "23": "<p>'I have sworn by myself; a righteous word has gone out from my mouth, and it will not turn back: To me every knee shall bow, every tongue shall swear allegiance' — the divine oath and the universal confession: 'bi nishbati = by myself I have sworn.' YHWH cannot swear by anything greater than himself (Heb 6:13: 'since there was no one greater for him to swear by, he swore by himself'), so the oath bi (by myself) = the highest possible guarantee. 'A righteous word has gone out from my mouth, and it will not turn back' (yatsa mippi tsedaqah davar velo yashuv = there has gone out from my mouth a word of righteousness and it will not return) — the irresistible prophetic word (55:11: 'my word that goes out from my mouth will not return to me empty'). 'To me every knee shall bow, every tongue shall swear allegiance' (kol-berekh tikra kol-lashon tishava = every knee will bow, every tongue will swear). Paul quotes this in Phil 2:10-11 for the universal acknowledgment of Christ as Lord; Rom 14:11 for the divine judgment.</p>",
    "24": "<p>'Only in the LORD, it will be said, are righteousness and strength; all who were angry with him will come to him and be ashamed' — the universal resolution: 'akh beLYHWH li yomer = only in YHWH, it will be said for me.' The akh (only/surely = the exclusive particle; righteousness and strength are found only in YHWH). 'Righteousness and strength' (tsedaqot va'oz = righteousnesses and strength) — the two divine attributes that the nations need and only YHWH provides: tsedaqot (the plural = the many righteous acts) and oz (the strength/power that backs them). 'All who were angry with him will come to him and be ashamed' (ve'edaiv yabo'u veiyevoshu kol-hacharim bo = and to him will come and be ashamed all those who were incensed against him) — the coming-to-shame is the recognition-in-shame of those who opposed YHWH: not their destruction but their conversion through the shame of realizing they were wrong.</p>",
    "25": "<p>'In the LORD all the offspring of Israel shall be found righteous and shall exult' — the final promise: 'beLYHWH yitsdaqo veythehallelu kol-zera Yisrael = in YHWH all the offspring of Israel will be declared righteous and will glory/boast.' The yitsdaqo (will be declared/found righteous = from tsaddiq = the legal declaration of righteousness, justification) 'in YHWH' (beLYHWH = in YHWH, not in themselves) — Israel's righteousness is not self-achieved but found in YHWH. The yithehallelu (will boast/glory = from halal = praise; the boasting is praise-boasting, hallelujah-boasting) = the ultimate resolution: Israel vindicated before the nations, boasting not in their own merit but in YHWH. Jer 9:24: 'let the one who boasts boast about this: that they understand and know me'; 1 Cor 1:31: 'let the one who boasts boast in the Lord.'</p>"
  },
  "46": {
    "1": "<p>Isaiah 46:1 opens the taunt against Babylon's gods with their humiliation: 'kar Bel kara Nevo = Bel bows down; Nebo stoops.' Bel (= Marduk = the chief god of Babylon; Bel means 'lord' = the same Semitic root as the Canaanite Baal; Marduk was identified with Enlil and called Bel = his great temple Esagila with its ziggurat Etemenanki was one of the wonders of the ANE). Nebo (= Nabu = the scribal god, patron of literacy and wisdom, son of Marduk; his great temple Ezida was at Borsippa, visible from Babylon). Both names appear in Babylonian royal names: Nebuchadnezzar (Nabu-kudurri-usur), Nabonidus (Nabu-na'id), Belshazzar (Bel-shar-usur). 'Their idols are loaded onto animals and cattle; the things you bear are burdens on exhausted beasts' — in the Babylonian Akitu (New Year) festival, the cult-statues of Bel and Nebo were carried in procession through Babylon on elaborately decorated sledges pulled by oxen. When Cyrus conquered Babylon, these same gods were looted — the procession-statues became war-plunder on pack animals.</p>",
    "2": "<p>'They stoop and bow down together; they cannot save the load — they themselves go into captivity' — the double humiliation of Babylon's gods: 'qaresu kare'u yachdav lo yakhellu mallit massah = they stooped and bowed down together; they could not save/deliver the burden/load.' The gods who were supposed to protect Babylon cannot even protect themselves — they are 'the burden' (massah = the carried load) on the pack animals, and they cannot 'deliver the burden' (mallit massah = save the load = they themselves are the cargo that cannot save itself). 'They themselves go into captivity' (venaphsham bashebi halakha = their own souls/selves went into captivity) — the gods of Babylon are taken captive when Babylon falls. The theology: when Babylon was defeated, the Babylonians would naturally interpret this as their gods' defeat. Isaiah agrees: the gods have gone into captivity. But YHWH has not been defeated — he orchestrated the entire event.</p>",
    "3": "<p>'Listen to me, O house of Jacob, and all the remnant of the house of Israel, you who have been carried since before birth, borne since the womb' — the contrast with the idol-gods who need carrying: 'shim'u elai beit-Ya'aqov vekhol she'erit beit Yisrael = listen to me, house of Jacob, and all the remnant of the house of Israel.' The she'erit (remnant = the theologically loaded term for the survivors of divine judgment who carry the covenant forward; 10:20-22; 37:31-32). 'You who have been carried since before birth' (hannessuim min-beten = the ones carried from the belly/womb) — the participle hannessuim (carried ones) = Israel as the ones YHWH has been carrying from before birth. The contrast with Bel and Nebo: the Babylonian gods need to be carried by animals; YHWH has been carrying Israel since before they were born.</p>",
    "4": "<p>'Even to your old age I am he, and even to gray hairs I will carry you. I have made you, and I will sustain you; I will carry you and save you' — YHWH's life-span commitment: 've'ad-ziknah ani hu ve'ad-sevah ani esbol = and to old age I am he, and to gray hairs I will carry.' The four-fold divine promise: (1) 'I am he' (ani hu = the divine self-identification of 41:4; 43:10-13; 48:12); (2) 'I will carry' (esbol = from saval = to carry as a burden, to sustain under weight; the heaviest kind of carrying); (3) 'I have made you' (ani asiti); (4) 'I will sustain and carry and save' (va'ani essa va'ani esbol va'amallet = I will carry and I will sustain and I will deliver/save). The life-span: from womb (v3) to old age/gray hairs (v4) = YHWH carries Israel through the entire arc of existence. The four-fold chiasm of carrying concludes with deliverance — the entire carrying-project has salvation as its end.</p>",
    "5": "<p>'To whom will you compare me and make me equal, and liken me, that we may be alike?' — the incomparability question mid-chapter: 'le-mi tedammeyuni vetashvu = to whom will you liken me and make me equal?' The three comparison-terms: (1) damah (liken); (2) shavah (make equal); (3) mashal (compare). The 'that we may be alike' (venidammeh = and we will be compared/equal) — the invitation to find a divine category-companion for YHWH. The question resumes the incomparability section of 40:18-26 after the Babylon-god-humiliation of vv1-4. The contrast: the gods that are carried vs. YHWH who carries; the gods who go into captivity vs. YHWH who redeems from captivity. No comparison is possible.</p>",
    "6": "<p>'Those who pour out gold from their purses and weigh out silver in the scales hire a goldsmith, who makes it into a god; then they fall down and worship it' — the wealthy man's idol-making: 'hazzelim zahav mikkis vekhesef baqaneh yishqqolu = those who lavish gold from the purse and silver they weigh in the scales.' The careful weighing of precious metals (the ancient payment system before coinage) for the idol-commission. 'Hire a goldsmith, who makes it into a god' (yiskeru tsaref veyesuhu El = they hire a goldsmith and he makes it into a god). The commercial transaction that produces a 'god': the idol is literally purchased. 'Then they fall down and worship it' (af-yishtachabu af-yisgadu = also they bow and also they prostrate). The progression: careful financial investment → commissioned manufacture → worship of the purchased object. The economic absurdity is complete: wealth spent on creating an object that is then worshiped as if it created wealth.</p>",
    "7": "<p>'They hoist it onto their shoulder, they carry it and set it in its place, and there it stands; it cannot move from its spot. If someone cries out to it, it gives no answer and rescues no one from trouble' — the four failures of the purchased god: (1) 'yissahuhu al-khatef yisvuluhu = they lift it on the shoulder, they carry it' — the god cannot transport itself; (2) 'vayannichuhw tachatav vaya'amod = and they set it down under it and it stands' — the god cannot stand up by itself; (3) 'lo-yamus mimmaqomo = it cannot move from its spot' — the god cannot move at all; (4) 'af-yitsa'aq elav velo ya'aneh = also one cries out to it and it does not answer; mitsaratho lo yoshiannu = from his trouble he does not save him' — the idol cannot hear prayer and cannot deliver from trouble (the primary test of deity: saving). 1 Kgs 18:26: 'Baal! Baal!' — no response, no voice, no answer.</p>",
    "8": "<p>'Remember this and stand firm; bring it to mind, you rebels' — the summons to memory and stability: 'zikhru-zot vehitashoshashu = remember this and stand firm/be resolute.' The hitashoshashu (stand firm = from asheshah = to be firm, confirmed; an unusual word perhaps from esh = fire = 'be fired up/steadfast'). 'Bring it to mind, you rebels' (hashivu al-lev posh'im = bring it back to your heart, O transgressors/rebels). The posh'im (transgressors/rebels = from pasha = to rebel, the covenant violation term of 1:2; 43:27; 48:8) addressed as the audience: even the rebels among Israel are summoned to remember. The 'this' (zot = this) that must be remembered = the entire argument of vv1-7: the idol-gods go into captivity while YHWH carries Israel.</p>",
    "9": "<p>'Remember the former things of long ago; for I am God, and there is no other; I am God, and there is none like me' — the dual incomparability statement: 'zikhru rishonut me'olam = remember the former things from antiquity.' The rishonut (former things = the saving acts of YHWH in primordial history: the Exodus, the wilderness, the conquest) as the evidence-base for trust. 'For I am God, and there is no other' (ki anoki El ve'en od = for I am God and there is no other) and 'I am God, and there is none like me' (Elohim ve'efes kamooni = God and there is no one like me). The two complementary claims: (1) there is no other in the divine category (en od = none besides); (2) there is no one similar to me (efes kamooni = there is no equivalent/likeness of me). Both claims together: no other deity exists, and even hypothetically no such being could resemble YHWH.</p>",
    "10": "<p>'Declaring the end from the beginning, and from ancient times things not yet done, saying, My plan shall stand, and I will carry out my purpose' — YHWH's unique predictive capacity: 'maggid mere'shit acharit = declaring from the beginning the end.' The beginning-to-end prediction: YHWH knows and declares the acharit (end/outcome) from the re'shit (beginning = the very first moment). This is not merely prediction but the declaration of the divine plan from its inception. 'From ancient times things not yet done' (umiqedem asher lo-naastu = and from antiquity things not yet done) — before the events happen, YHWH announces them. 'Saying, My plan shall stand, and I will carry out my purpose' (omer atsati taqum vekhol-chefetsi e'eseh = saying: my counsel will stand and all my pleasure I will do). The atsah (plan/counsel = the divine plan; 5:19: 'his plan draws near'; 25:1: 'your counsel of old is faithful and true') that stands unalterably.</p>",
    "11": "<p>'Calling a bird of prey from the east, the man of my purpose from a far country. I have spoken, and I will bring it about; I have planned, and I will do it' — the Cyrus-bird oracle: 'qore miqqedem ayit = calling from the east a bird of prey.' The ayit (bird of prey = a swift-flying predatory bird; possibly an eagle, hawk, or vulture) from the east = Cyrus, whose campaigns swept from the east with remarkable speed (the eagle-speed of military movement: Deut 28:49: 'a nation that swoops down on you like an eagle'). 'The man of my purpose from a far country' (ish atsati me'erets merchaq = the man of my counsel from a far land) = Cyrus as the embodiment of YHWH's atsah (plan/purpose). 'I have spoken, and I will bring it about; I have planned, and I will do it' (af-dibarti af-avi'ennah yatsarti af-e'esennah = indeed I spoke, indeed I will bring it; I formed/planned, indeed I will do it) — the divine word-to-act sequence: speech precedes and guarantees action.</p>",
    "12": "<p>'Listen to me, you stubborn of heart, you who are far from righteousness' — the appeal to the hardened exiles: 'shim'u elai abirei-lev = listen to me, you mighty-of-heart/stubborn of heart.' The abirei-lev (mighty ones of heart = the stiff-hearted, those whose inner resolve is hardened against divine appeal; from abbir = mighty, strong) — the 'stubborn of heart' is not a neutral strength but the obstinacy of those who resist YHWH's persuasion. 'Who are far from righteousness' (harecho'kim mittsedaqah = the far ones from righteousness) — tsedaqah as the covenant right-ordering that defines the proper relationship with YHWH: these are the exiles who have concluded that YHWH has abandoned them or cannot fulfill his promises, and so have positioned themselves far from him in their hearts.</p>",
    "13": "<p>'I am bringing my righteousness near — it is not far off — and my salvation will not linger; I will put salvation in Zion, for Israel my glory' — the answer to the 'far from righteousness' of v12: 'qaravti tsidqati lo tirchaq = I have brought near my righteousness, it will not be far.' The reversal: those far from righteousness (v12) find YHWH's righteousness coming near to them. 'My salvation will not linger' (uteshu'ati lo te'acheer = and my salvation will not delay). 'I will put salvation in Zion' (venatatti beVTsiyon teshu'ah = and I will give in Zion salvation) — Zion as the place where divine salvation is established and from which it radiates (cf. 2:3: 'from Zion shall go forth the law, and from Jerusalem the word of YHWH'). 'For Israel my glory' (leYisrael tif'arti = for Israel my splendor/beauty/glory) — Israel as YHWH's tif'arah (the beautiful thing in which he takes pride and displays his character; 44:23: 'displays his glory in Israel').</p>"
  },
  "47": {
    "1": "<p>Isaiah 47:1 opens the taunt-song against Babylon with a royal demotion: 'redi veshevi al-afar betulat bat-Bavel = come down and sit in the dust, O virgin daughter of Babylon.' The 'virgin daughter of Babylon' (betulat bat-Bavel = the unviolated/inviolable city, proud and hitherto unconquered) is commanded to descend from her throne to the dust — the posture of the humiliated, those in mourning, and the utterly defeated (Job 2:8: Job sat in the ashes; Lam 2:10: 'the elders of Daughter Zion sit on the ground in silence'). 'Sit on the ground without a throne' (shevi la'arets en-kisse bat-Kasdim = sit to the ground without a throne, O daughter of Chaldeans) — the throne (kisse) as the symbol of sovereign power now removed. 'For you will no longer be called tender and delicate' (ki lo tosiphi yiqrehu lakh rakkah va'anugah = for you will no longer be called tender and pampered) — the imperial city's self-image as refined, luxurious, and untouchable is stripped away.</p>",
    "2": "<p>'Take the millstones and grind flour; remove your veil, take off your robe, bare your legs, and wade through the rivers' — the slave's degradation imposed on the queen-city: 'qichi rechayim vetchani qemach = take millstones and grind flour.' The rechayim (millstones = the stone hand-mill for grinding grain, the work assigned to the lowest-ranking slave women: Exod 11:5: 'from the firstborn of Pharaoh...to the firstborn of the female slave, who is at the handmill'; Num 11:8; Matt 24:41). 'Remove your veil' (galli tsammatekh = uncover/expose your tresses/veil) — the veil in ANE culture was the mark of a free, honorable woman; removing it was the mark of a slave or prostitute (Gen 24:65: Rebekah covered herself when she saw Isaac; the Assyrian Middle Assyrian Laws specify that slaves and prostitutes were forbidden to veil). 'Bare your legs, and wade through the rivers' (gali-shok ivri neharot = uncover the leg, cross through rivers) — the posture of a slave being led across water by a captor.</p>",
    "3": "<p>'Your nakedness shall be exposed, and your disgrace shall be visible. I will take vengeance, and I will not relent' — the public shaming: 'tiggaleh ervatekhah = your nakedness will be exposed.' The ervah (nakedness/exposure = the most extreme form of public humiliation in ANE culture; the exposure of a conquered city's nakedness in the prophets = the ultimate defeat: Ezek 16:37-38; Nah 3:5-6). 'And your disgrace shall be visible' (vegam tera'eh cherepatekhah = and also your disgrace/reproach will be seen) — the cherepah (reproach/disgrace = the social shame that results from public exposure; the same term as the Rabshakeh's 'reviling' of YHWH in 37:3). 'I will take vengeance, and I will not relent' (eqqom naqam velo efga adam = I will take vengeance and I will not intercede with/for a man) — the divine vengeance (naqam = the rightful retribution of a wronged party) executed without mercy. Deut 32:35: 'Vengeance is mine; I will repay.'</p>",
    "4": "<p>'Our Redeemer — the LORD of hosts is his name — the Holy One of Israel' — the doxological parenthesis: 'go'alenu YHWH tseva'ot shemo = our Redeemer, YHWH of hosts is his name.' The speaker shifts for one verse from YHWH's divine first-person to the community's third-person praise. Go'alenu (our Redeemer = our kinsman-redeemer, from the go'el institution of Lev 25; Ruth 4) — the community celebrating the identity of the one who judges Babylon on their behalf. YHWH tseva'ot (YHWH of hosts = the divine warrior-title; the title of the ark at Shiloh and Jerusalem, 1 Sam 1:3; 2 Sam 6:2) combined with qedosh Yisrael (the Holy One of Israel = Isaiah's distinctive title for YHWH throughout the book). The brief doxology interrupts the taunt-song to ensure the reader knows who is judging Babylon: Israel's covenant God, not a superior imperial power.</p>",
    "5": "<p>'Sit in silence and go into darkness, O daughter of the Chaldeans; for you will no longer be called the mistress of kingdoms' — the second demotion command: 'shevi dumam uvo'i bachhoshekh bat-Kasdim = sit in silence and go into the darkness, O daughter of Chaldeans.' The doman (silence = the silence of death and the grave; Ps 115:17: 'it is not the dead who praise the LORD... those who go down to the place of silence'; Ps 94:17: 'unless the LORD had been my help, my soul had soon dwelt in silence'). The darkness (choshekh) = the realm of judgment and humiliation contrasted with the light of YHWH's salvation (45:7: 'I form light and create darkness'). 'For you will no longer be called the mistress of kingdoms' (ki lo tosiphi yiqre'u lakh gevirat mamlakhot = for you will no longer be called the mistress of kingdoms) — gevirat (mistress/queen/lady = the feminine of gevir = master/lord; the title of the queen-mother in Judah, 1 Kgs 15:13; 2 Kgs 10:13). Babylon's imperial queenship ended.</p>",
    "6": "<p>'I was angry with my people; I desecrated my heritage; I handed them over to you; but you showed them no mercy; on the elderly you laid a very heavy yoke' — the divine explanation and the charge against Babylon: 'qatsafti al-ammi chilarti nachalati = I was angry with my people, I profaned my heritage.' The qatsafti (I was angry = the righteous anger of YHWH producing the exile as judgment) and chillalti (I profaned/desecrated = I allowed my inheritance to be treated as common, stripped of its sacred status). 'I handed them over to you' (va'ettem beyadekhah = and I gave them into your hand) — the divine authorization of Babylon's role: Babylon was YHWH's instrument of judgment (10:5-6: 'Assyria, the rod of my anger'). 'But you showed them no mercy' (lo-samit lahem rachamim = you did not set mercies on them) — the charge: Babylon exceeded its mandate. 'On the elderly you laid a very heavy yoke' (al-zaqen hikbadti ullakh me'od = on the elder you made the yoke very heavy) — the abuse of the most vulnerable (elderly people) as the specific evidence of cruelty beyond the divine commission.</p>",
    "7": "<p>'You said, I will be mistress forever, so that you did not take these things to heart or consider how it would end' — Babylon's fatal assumption of permanence: 'vattemeri le'olam ehyeh gevirah = and you said: forever I will be mistress.' The le'olam (forever = the permanent self-perpetuation that only YHWH can claim: Ps 90:2: 'from everlasting to everlasting you are God'). Babylon claimed for itself the permanence that belongs only to YHWH. 'So that you did not take these things to heart' (lo-samti elleh al-libbakh = you did not set these things to your heart) — the absence of reflection on the contingent nature of Babylon's power. 'Or consider how it would end' (lo zakharti acharitah = you did not remember its end) — the acharit (end/outcome = the outcome that wisdom requires consideration of; Prov 14:12: 'there is a way that appears right, but in the end it leads to death'). Babylon's failure of wisdom: not considering how imperial power ends.</p>",
    "8": "<p>'Now therefore hear this, you lover of pleasures, who sit so securely, who say in your heart, I am, and there is no one besides me; I will never sit as a widow or know the loss of children' — Babylon's self-deification: 'veat'ah shim'i zot addinah hayoshevet lavetach = and now hear this, O pleasure-loving one who sits in security.' The adinah (pleasure-lover = the one given to luxury, sensual pleasure, self-indulgence; Jer 51:34 uses similar vocabulary for Babylon). 'Who say in your heart, I am, and there is no one besides me' (ha'omeret bilibah ani ve'afsi od = who says in her heart: I am, and there is nothing besides me) — the 'I am, and there is no other' (ani ve'efsi od) = the exact language YHWH uses of himself in 45:5-6, 14, 18, 21-22; 46:9. Babylon blasphemously appropriates the divine uniqueness-formula for the imperial city. Rev 18:7 quotes this verse directly for the end-time Babylon: 'she says in her heart: I sit as queen; I am not a widow; I will never see grief.'</p>",
    "9": "<p>'Both of these things shall come upon you in a moment, in a single day: loss of children and widowhood — they shall come on you in full, despite your many sorceries and the great power of your spells' — the sudden reversal of both claims: 'vetavanah lakh shtei elleh rega beyom echad = and these two things will come upon you in a moment, in a single day.' The two things Babylon claimed would never happen (widowhood and childlessness, v8) come simultaneously and instantly — 'in a moment, in a single day.' 'Despite your many sorceries' (bekhovved keshafayikh me'od = despite the great abundance of your sorceries) — the keshafim (sorceries/witchcraft = the Babylonian magical arts: incantations, protective rituals, divination). 'And the great power of your spells' (uvaottsmat chovareikh me'od = and the great strength of your spellbinders/charm-casters) — the Babylonian professional magical class (chovrim = those who bind spells). Despite the most sophisticated magic system in the ANE, the judgment cannot be averted.</p>",
    "10": "<p>'You trusted in your wickedness; you said, No one sees me; your wisdom and your knowledge led you astray, and you said in your heart, I am, and there is no one besides me' — the three grounds of Babylon's false confidence: (1) 'vattevchechi bera'atekh = you trusted in your wickedness' — the confidence born of a history of successfully doing evil without punishment (cf. Eccl 8:11: 'when the sentence for a crime is not quickly carried out, people's hearts are filled with schemes to do wrong'); (2) 'amart ein ro'ani = you said: no one sees me' — the claim of divine non-surveillance (Ps 10:11: 'he hides his face and never sees'; Job 22:13: 'how can God know? Does he judge through such darkness?'); (3) 'chakhmateikh veda'takh hi shevatekha = your wisdom and your knowledge — they have led you astray' — the Babylonian epistemic arrogance: the sophisticated knowledge systems that Babylon prided itself on (astronomy, divination, mathematics) became the mechanism of their self-deception. The second occurrence of 'I am, and there is no one besides me' (v8's formula repeated) = the imperial self-deification as the theological ground of Babylon's judgment.</p>",
    "11": "<p>'But evil shall come upon you, which you will not know how to conjure away; disaster shall fall on you, which you will be powerless to avert; and ruin shall come upon you suddenly, which you never saw coming' — the triple disaster announcement: (1) 'vetavo aleikh ra'ah lo ted'i shacharah = and evil will come upon you, you will not know its dawn/how to avert it' — the ra'ah (evil/disaster) coming without warning or means of avoidance; (2) 'vetippol aleikh hovah lo tukhal kapparoh = and disaster will fall on you, you will not be able to atone for/avert it' — the kapparoh (atonement/covering = the ritual means of covering/removing guilt or danger; Yom Kippur = the Day of Atonement). Babylon's own atonement-rituals will be powerless against YHWH's judgment; (3) 'vetavo aleikh pit'om shoah asher lo-tede'i = and ruin will come upon you suddenly, a desolation you did not know' — the shoah (sudden ruin/disaster; the same root as the Holocaust's name in Hebrew) coming without warning. Cyrus's conquest of Babylon in 539 BCE was indeed remarkably sudden and unexpected.</p>",
    "12": "<p>'Stand by your enchantments and your many sorceries, which you have practiced since your youth; perhaps you will succeed; perhaps you can inspire fear' — the divine sarcasm inviting Babylon to try its magical arts: 'imdiy-na beverakhayikh uvrov kheshafayikh asher yaga'at mine'urayikh = stand now in your enchantments and your many sorceries in which you have labored since your youth.' The me'urayikh (since your youth = Babylon's magical arts were ancient, developed over centuries of Mesopotamian civilization going back to Sumer). 'Perhaps you will succeed; perhaps you can inspire fear' (ulai tukeli ho'il ulai ta'arotsi = perhaps you can prevail; perhaps you will inspire awe/fear) — the sarcastic 'perhaps' (ulai): in the face of YHWH's judgment, the most the magical arts can offer is a 'perhaps.' The entire history of Babylonian divination — the omen series, the astrological texts, the incantation rituals — is dismissed as offering only tentative and ineffectual results against divine action.</p>",
    "13": "<p>'You are worn out by all your advisers; let them stand up and save you — those who divide the sky, who gaze at the stars, who at each new moon predict what will happen to you' — the exhaustion of Babylonian knowledge-systems: 'nile'it berov atsotayikh = you are wearied by the multitude of your counselors.' Three classes of Babylonian religious specialists: (1) 'chotevei shamayim = those who divide/cut the sky' = the astrologers who divided the heavens into zones for omen-interpretation (the Babylonian system divided the sky into three 'roads': the Road of Anu, the Road of Enlil, and the Road of Ea); (2) 'hachozim bakokahvim = those who gaze at the stars' = the astronomical observers who tracked planetary and stellar movements (the Babylonian astronomical cuneiform texts represent the most sophisticated pre-modern astronomy, with accurate records of planetary cycles, eclipses, etc.); (3) 'meyodi'im lechadashim = those who make known by months' = the monthly prognosticators who issued monthly horoscope-style predictions (the Babylonian Almanacs and Goal-Year texts). All three classes of expert are invited to save Babylon — knowing the outcome in advance.</p>",
    "14": "<p>'Look — they are like straw; the fire devours them; they cannot save themselves from the power of the flame. There is no coal for warmth, no fire to sit by' — the judgment by fire: 'hineh hayu kaqash esh serapatam = see, they are like straw; fire has burned them.' The astrologers and diviners compared to qash (straw/chaff = the light, inflammable residue of the threshing floor, the same chaff that the wind blows away in 40:24; 41:16). 'They cannot save themselves from the power of the flame' (lo-yatsillu et-nafsham miyad lehabah = they cannot deliver their souls from the hand of the flame). The irony: the specialists who were supposed to 'save' Babylon from disaster cannot save themselves. 'There is no coal for warmth, no fire to sit by' (ein-gachelet lehamam ur lagshevet legandeha = there is no coal to warm, no fire to sit before it) — the fire of judgment produces no warmth or benefit, only destruction. Contrast with the idol-maker's fire in 44:16 ('Aha, I am warm!').</p>",
    "15": "<p>'Such are those you have dealt with, who have been your trading partners since your youth; they each go off in their own direction; there is no one to save you' — the dissolution of Babylon's commercial network: 'ken hayu lakh asher yaga'at socharayikh mine'urayikh = such are those to you for whom you have labored, your traders from your youth.' The trading partners (sokherayikh = your merchants/traders) who have benefited from Babylon's commercial empire 'since your youth' (mine'urayikh = from your youth = the centuries of Babylonian commercial dominance). 'They each go off in their own direction' (ish ledarkho ta'u = each wanders to his own path) — the commercial abandonment: when Babylon falls, the trading partners scatter, each pursuing their own survival. 'There is no one to save you' (en moshi'ekh = there is no one saving you) — the final verdict: the trading partners, the astrologers, the enchanters — all fail to save. Only YHWH is moshi'a (savior = 43:11; 45:21), and he is judging Babylon, not protecting it. Rev 18:9-19 expands this commercial-abandonment motif for the eschatological Babylon.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
